const { day, leads, config } = $input.first().json.body;
const freq = config.reminders.frequencyDays;
const maxR = config.reminders.maxReminders;
let idCounter = Date.now();
function uid() { return `a${idCounter++}`; }
function ts() { return new Date().toISOString(); }
function budgetScore(b) { return b > 2000 ? 10 : b >= 500 ? 6 : 3; }
function intentScore(s) { return s === 'high' ? 9 : s === 'medium' ? 6 : 3; }
function timelineScore(d) { return d <= 7 ? 10 : d <= 21 ? 6 : 3; }
function computeScore(lead) {
  const bs = budgetScore(lead.formInputs.budget);
  const is = intentScore(lead.intentSignal);
  const tss = timelineScore(lead.formInputs.timelineDays);
  const { budgetWeight, intentWeight, timelineWeight } = config.scoring;
  const raw = (bs * budgetWeight + is * intentWeight + tss * timelineWeight) / 100;
  const score = Math.round(raw);
  const classification = score >= 7 ? 'Hot' : score >= 4 ? 'Warm' : 'Cold';
  return { score, classification, rationale: `Budget ${bs}/10, Intent ${is}/10, Timeline ${tss}/10` };
}
function seeded(leadId, salt) {
  const str = leadId + salt;
  let hash = 0;
  for (const c of str) hash = ((hash << 5) - hash) + c.charCodeAt(0);
  return (Math.abs(hash) % 10000) / 10000;
}
function getStory(lead) {
  if (lead.score >= 7) {
    const replyRel = 2 + Math.floor(seeded(lead.id, 'reply') * 3);
    return { staffCallDay: 2, customerReplyDay: replyRel, meetingDay: replyRel, closeDay: replyRel + 2 };
  } else if (lead.score >= 4) {
    const replies = seeded(lead.id, 'replies') < 0.6;
    const closes = replies && seeded(lead.id, 'closes') < 0.5;
    const replyRel = 4 + Math.floor(seeded(lead.id, 'reply') * 4);
    return { staffCallDay: 3, customerReplyDay: replies ? replyRel : null, meetingDay: closes ? replyRel : null, closeDay: closes ? replyRel + 2 : null };
  }
  return { staffCallDay: null, customerReplyDay: null, meetingDay: null, closeDay: null };
}
const allActions = [];
const leadUpdates = {};
for (const lead of leads) {
  const rel = day - lead.registeredOnDay;
  const actions = [];
  const updates = {};
  const story = getStory(lead);
  if (rel === 1) {
    const { score, classification, rationale } = computeScore(lead);
    updates.score = score; updates.classification = classification; updates.status = 'Contacted'; updates.nextReminderDay = day + freq;
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `Onboarding email sent to ${lead.name}`, detail: { channel: 'Email', subject: `Welcome — let's talk`, body: `Hi ${lead.name},\n\nThanks for reaching out! Budget $${lead.formInputs.budget}, timeline ${lead.formInputs.timelineDays} days.\n\n— ${lead.assignedRep}` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'score_update', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `Lead scored ${score}/10 — ${classification}`, detail: { score, classification, rationale, weights: config.scoring }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'rep_assigned', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} assigned to ${lead.name}`, detail: { rep: lead.assignedRep, note: `${classification} lead — ${score}/10.` }, timestamp: ts() });
    if (score >= 4) actions.push({ id: uid(), day, type: 'proposal_sent', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} mailed proposal to ${lead.name}`, detail: { rep: lead.assignedRep, subject: 'Project Proposal', body: `Hi ${lead.name},\n\nBudget: $${lead.formInputs.budget}, Timeline: ${lead.formInputs.timelineDays} days.\n\n— ${lead.assignedRep}` }, timestamp: ts() });
  }
  if (story.staffCallDay !== null && rel === story.staffCallDay && !['Closed Won','Closed Lost','Nurture'].includes(lead.status)) {
    actions.push({ id: uid(), day, type: 'call_logged', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} called ${lead.name} — left voicemail`, detail: { rep: lead.assignedRep, notes: 'Called to follow up on proposal. No answer — left voicemail.' }, timestamp: ts() });
  }
  const alreadyReplied = ['Replied','Meeting Scheduled','Closed Won','Nurture'].includes(lead.status);
  if (story.customerReplyDay !== null && rel === story.customerReplyDay && !alreadyReplied) {
    const isHot = lead.score >= 7;
    actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: lead.name, actor: 'customer', summary: isHot ? `${lead.name} replied: ready to move` : `${lead.name} replied: interested but busy`, detail: { from: lead.email, body: isHot ? 'Ready to move fast — can we schedule a call?' : 'Interested but hectic. Follow up in a week?' }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `AI drafted reply sent to ${lead.name}`, detail: { subject: 'Re: Project Proposal', body: isHot ? `Hi ${lead.name},\n\nAbsolutely — booking link below.\n\n— ${lead.assignedRep} (via CloseIt AI)` : `Understood ${lead.name} — I'll check back in a week.\n\n— ${lead.assignedRep} (via CloseIt AI)` }, timestamp: ts() });
    if (story.meetingDay === rel) { actions.push({ id: uid(), day, type: 'meeting_scheduled', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `Discovery call booked with ${lead.name}`, detail: { date: `Day ${day + 1}`, rep: lead.assignedRep, nudge: true }, timestamp: ts() }); updates.status = 'Meeting Scheduled'; }
    else { updates.status = 'Replied'; }
    updates.nextReminderDay = null;
  }
  if (story.closeDay !== null && rel === story.closeDay && !['Closed Won','Closed Lost'].includes(lead.status)) {
    actions.push({ id: uid(), day, type: 'call_logged', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} completed discovery call with ${lead.name}`, detail: { rep: lead.assignedRep, notes: 'Strong fit. Proceeding to agreement.' }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'closed_won', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `🎉 ${lead.name} closed won by ${lead.assignedRep}`, detail: { rep: lead.assignedRep, value: `$${lead.formInputs.budget}`, note: 'Agreement signed.' }, timestamp: ts() });
    updates.status = 'Closed Won'; updates.nextReminderDay = null;
  }
  const onSpecialDay = story.customerReplyDay === rel || story.closeDay === rel;
  const engaged = ['Replied','Meeting Scheduled','Closed Won','Closed Lost','Nurture'].includes(lead.status);
  if (!onSpecialDay && !engaged && lead.nextReminderDay === day && lead.remindersSent < maxR) {
    const rn = lead.remindersSent + 1;
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `Follow-up #${rn} sent to ${lead.name} (AI-drafted)`, detail: { subject: rn === 1 ? `Quick check-in — ${lead.name}` : `Last note from us — ${lead.name}`, body: rn === 1 ? `Hi ${lead.name},\n\nJust checking in on the proposal.\n\n— ${lead.assignedRep} (via CloseIt AI)` : `Hi ${lead.name},\n\nFinal note — reply any time.\n\n— ${lead.assignedRep} (via CloseIt AI)` }, timestamp: ts() });
    updates.remindersSent = rn;
    if (rn >= maxR) { updates.status = 'Nurture'; updates.nextReminderDay = null; actions.push({ id: uid(), day, type: 'moved_to_nurture', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `${lead.name} moved to Nurture`, detail: { reason: `${maxR} follow-ups, no response.` }, timestamp: ts() }); }
    else { updates.nextReminderDay = day + freq; updates.status = 'Awaiting Reply'; }
  }
  allActions.push(...actions);
  if (Object.keys(updates).length > 0) leadUpdates[lead.id] = updates;
}
return [{ json: { day, actions: allActions, leadUpdates } }];

// Split the actions array into individual items for Sheets append
const { day, actions, leadUpdates } = $input.first().json;

if (!actions || actions.length === 0) {
  // No actions — return a dummy item to keep the flow going
  return [{ json: { _noActions: true, day, leadUpdates } }];
}

return actions.map(action => ({
  json: {
    lead_id: action.leadId,
    day: action.day,
    action_type: action.type,
    actor: action.actor,
    summary: action.summary,
    detail_json: JSON.stringify(action.detail || {}),
    timestamp: action.timestamp
  }
}));
